INSERT INTO offer (offer_id, start_date, end_date, create_date, update_date, create_user, update_user, pet_id, title, frequency, care_type, animal_type, offer_type, price, description, status) SELECT UUID_TO_BIN(UUID()), DATE_ADD(CURDATE(), INTERVAL 7 DAY), DATE_ADD(CURDATE(), INTERVAL 14 DAY), CURRENT_TIMESTAMP(6), CURRENT_TIMESTAMP(6), u.id, u.id, p.id, 'Wochenendbetreuung - Balu', 'REGULAR', 'PET_SITTING', 'DOG', 'OWNER_OFFER', 75.00, 'Suche zuverlässige Betreuung für unseren Golden Retriever Balu am Wochenende.', 'OPEN' FROM user u JOIN pet p ON p.owner_id = u.id WHERE u.email = 'anna.mueller@petsitter.local' AND p.name = 'Balu' AND NOT EXISTS (SELECT 1 FROM offer WHERE create_user = u.id AND title = 'Wochenendbetreuung - Balu');
INSERT INTO offer (offer_id, start_date, end_date, create_date, update_date, create_user, update_user, pet_id, title, frequency, care_type, animal_type, offer_type, price, description, status) SELECT UUID_TO_BIN(UUID()), DATE_ADD(CURDATE(), INTERVAL 30 DAY), DATE_ADD(CURDATE(), INTERVAL 44 DAY), CURRENT_TIMESTAMP(6), CURRENT_TIMESTAMP(6), u.id, u.id, p.id, 'Urlaubsbetreuung 2 Wochen', 'ONE_TIME', 'PET_AND_HOUSE_SITTING', 'DOG', 'OWNER_OFFER', 700.00, 'Wir fahren in den Urlaub und suchen jemanden, der Balu betreut und auf unser Haus aufpasst.', 'OPEN' FROM user u JOIN pet p ON p.owner_id = u.id WHERE u.email = 'anna.mueller@petsitter.local' AND p.name = 'Balu' AND NOT EXISTS (SELECT 1 FROM offer WHERE create_user = u.id AND title = 'Urlaubsbetreuung 2 Wochen');
INSERT INTO offer (offer_id, start_date, end_date, create_date, update_date, create_user, update_user, pet_id, title, frequency, care_type, animal_type, offer_type, price, description, status) SELECT UUID_TO_BIN(UUID()), DATE_ADD(CURDATE(), INTERVAL 1 DAY), DATE_ADD(CURDATE(), INTERVAL 365 DAY), CURRENT_TIMESTAMP(6), CURRENT_TIMESTAMP(6), u.id, u.id, NULL, 'Hundebetreuung - Wochenende + Abende', 'REGULAR', 'PET_SITTING', 'DOG', 'SITTER_OFFER', 50.00, 'Biete zuverlässige und liebevolle Hundebetreuung am Wochenende und unter der Woche abends.', 'OPEN' FROM user u WHERE u.email = 'roland.sitter@petsitter.local' AND NOT EXISTS (SELECT 1 FROM offer WHERE create_user = u.id AND title = 'Hundebetreuung - Wochenende + Abende');
