INSERT INTO offer (offer_id, start_date, end_date, create_date, update_date, create_user, update_user, pet_id, title, frequency, care_type, animal_type, offer_type, price, description, status) SELECT UUID_TO_BIN(UUID()), DATE_ADD(CURDATE(), INTERVAL 1 DAY), DATE_ADD(CURDATE(), INTERVAL 365 DAY), CURRENT_TIMESTAMP(6), CURRENT_TIMESTAMP(6), u.id, u.id, NULL, 'Katzenbetreuung spezialisiert', 'REGULAR', 'PET_SITTING', 'CAT', 'SITTER_OFFER', 35.00, 'Spezialiste für Katzenbetreuung. Liebe Katzen und kann gut mit ihnen umgehen. Gerne auch Mehrkatzen-Haushalte.', 'OPEN' FROM user u WHERE u.email = 'roland.sitter@petsitter.local' AND NOT EXISTS (SELECT 1 FROM offer WHERE create_user = u.id AND title = 'Katzenbetreuung spezialisiert');
INSERT INTO offer (offer_id, start_date, end_date, create_date, update_date, create_user, update_user, pet_id, title, frequency, care_type, animal_type, offer_type, price, description, status) SELECT UUID_TO_BIN(UUID()), DATE_ADD(CURDATE(), INTERVAL 7 DAY), DATE_ADD(CURDATE(), INTERVAL 10 DAY), CURRENT_TIMESTAMP(6), CURRENT_TIMESTAMP(6), u.id, u.id, NULL, 'Suche Tiersitter für 3-Tages-Trip', 'ONE_TIME', 'PET_SITTING', 'CAT', 'OWNER_OFFER', 60.00, 'Kurzfristig: Fahre für ein Wochenende weg und suche jemanden, der auf meine Katze aufpasst.', 'OPEN' FROM user u WHERE u.email = 'roland.sitter@petsitter.local' AND NOT EXISTS (SELECT 1 FROM offer WHERE create_user = u.id AND title = 'Suche Tiersitter für 3-Tages-Trip');